import { useState,useEffect } from "react";
import {Link} from 'react-router-dom';
import axios from 'axios';
import { jwtDecode } from "jwt-decode";
import './AfficherUtilisateurs.css';

export default function Utilisateur(){
    const [users,setUsers] = useState([]);
    const [infos,setInfos] = useState([]);
    const token = localStorage.getItem("token");
        let r = null;
        if(token){
            const decoded = jwtDecode(token);
            r = decoded.role; 
        }
    const [username,setUsername] = useState('');
    const getUsers = async () => {
        const res = await axios.get('http://localhost:3001/users', {
          headers: { Authorization: `Bearer ${token}`}
        });
        setUsers(res.data);
    }
    useEffect(() => {
        getUsers();
    },[]);
    const nas = infos.length > 0 ? infos : users;
  
    return (
        <div className="users-container">
            <div className="users-header">
                <h1>Gestion des Utilisateurs</h1>
                <div className="search-section">
                    <input 
                        type="text" 
                        value={username} 
                        onChange={(e) => setUsername(e.target.value)}
                        placeholder="Rechercher par nom d'utilisateur..."
                        className="search-input"
                    />
                    <button 
                        onClick={async() => {
                            if (!username.trim()) {
                                setInfos([]);
                                return;
                            }
                            const res = await axios.get(`http://localhost:3001/searchUsername/${username}`, {
                                headers: { Authorization: `Bearer ${token}`}
                            });
                            setInfos(res.data);
                        }}
                        className="search-btn"
                    >
                        🔍 Rechercher
                    </button>
                </div>
                {r === "admin" && (
                    <Link to='/AjouterUtilisateur' className="add-user-btn">
                        ➕ Ajouter un utilisateur
                    </Link>
                )}
            </div>

            <div className="table-container">
                <table className="users-table">
                    <thead>
                        <tr>
                            <th>Nom d'utilisateur</th>
                            <th>Email</th>
                            <th>Rôle</th>
                            <th>Actions</th>
                            <th>Statut</th>
                        </tr>
                    </thead>
                    <tbody>
                        {nas.map((u,i) => (
                            <tr key={i} className="user-row">
                                <td>{u.username}</td>
                                <td>{u.email}</td>
                                <td>
                                    <span className={`role-badge ${u.role}`}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="actions-cell">
                                    {r === "admin" ? (
                                        <>
                                            <button 
                                                onClick={ async () => {
                                                    await axios.delete(`http://localhost:3001/delete/${u._id}`,{
                                                        headers: { Authorization: `Bearer ${token}` }
                                                    })
                                                    setUsers(prev => prev.filter(user => user._id !== u._id));
                                                }}
                                                className="action-btn delete-btn"
                                            >
                                                🗑️ Supprimer
                                            </button>
                                            <Link 
                                                to={`/modifierUtilisateur/${u._id}`}
                                                className="action-btn edit-btn"
                                            >
                                                ✏️ Modifier
                                            </Link>
                                        </>
                                    ) : (
                                        <span className="no-access">Accès limité</span>
                                    )}
                                </td>
                                <td>
                                    {r === "admin" ? (
                                        <button 
                                            onClick={ async ()=> {
                                                if(u.isBlocked){
                                                    await axios.put(`http://localhost:3001/unblock/${u._id}`,{},{
                                                        headers: { Authorization: `Bearer ${token}` }
                                                    });
                                                } else {
                                                    await axios.put(`http://localhost:3001/block/${u._id}`,{},{
                                                        headers: { Authorization: `Bearer ${token}` }
                                                    });
                                                }
                                                getUsers();
                                            }}
                                            className={`status-btn ${u.isBlocked ? 'unblock-btn' : 'block-btn'}`}
                                        >
                                            {u.isBlocked ? "🔓 Débloquer" : "🔒 Bloquer"}
                                        </button>
                                    ) : (
                                        <span className="no-access">Accès limité</span>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    )
}
